// No meetings found - just exit gracefully
return [{
  json: {
    success: true,
    message: 'No meetings require reminders at this time',
    timestamp: new Date().toISOString()
  }
}];

const meeting = $input.first().json;

// Format date/time for display
const meetingDateTime = new Date(meeting.date_time);
const dateStr = meetingDateTime.toLocaleDateString('en-US', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});
const timeStr = meetingDateTime.toLocaleTimeString('en-US', {
  hour: '2-digit',
  minute: '2-digit',
  hour12: true
});

// Clean phone numbers (remove + if present)
const cleanPhone = (phone) => {
  if (!phone) return null;
  return phone.replace(/\+/g, '');
};

const schedulerPhone = cleanPhone(meeting.scheduler_phone);
const contactPhone = cleanPhone(meeting.contact_phone);

// Message for the scheduler
const schedulerMessage = `⏰ **Meeting Reminder**\n\nYour meeting is starting in 30 minutes!\n\n📅 **${meeting.title}**\n👤 With: ${meeting.contact_name}\n🕐 Time: ${dateStr} at ${timeStr}\n📍 Location: ${meeting.location}\n📋 Purpose: ${meeting.purpose}\n\nPlease prepare accordingly.`;

// Message for the contact/end-user
const contactMessage = `⏰ **Meeting Reminder**\n\nYour meeting is starting in 30 minutes!\n\n📅 **${meeting.title}**\n🕐 Time: ${dateStr} at ${timeStr}\n📍 Location: ${meeting.location}\n📋 Purpose: ${meeting.purpose}\n\nLooking forward to meeting with you!`;

return [{
  json: {
    meetingId: meeting.id,
    schedulerPhone: schedulerPhone,
    schedulerMessage: schedulerMessage,
    contactPhone: contactPhone,
    contactMessage: contactMessage,
    contactName: meeting.contact_name,
    meetingTitle: meeting.title,
    meetingTime: `${dateStr} at ${timeStr}`
  }
}];

const data = $('Format Reminder Messages').first().json;

return [{
  json: {
    success: true,
    message: `✅ Reminder sent for meeting: ${data.meetingTitle}`,
    details: {
      meetingId: data.meetingId,
      contactName: data.contactName,
      meetingTime: data.meetingTime,
      schedulerNotified: !!data.schedulerPhone,
      contactNotified: true,
      timestamp: new Date().toISOString()
    }
  }
}];

// Format search results
const results = $input.all().flatMap(item => item.json);

// Get search term from previous node
const validateItems = $items("Validate Input1");
const searchTerm = (validateItems?.[0]?.json?.contact_name || 'Unknown').trim();

// Handle no results
if (!results || results.length === 0) {
  return [{
    json: {
      success: false,
      message: `❌ No contacts found matching "${searchTerm}".`,
      contacts: [],
      count: 0,
      intent: 'search'
    }
  }];
}

// Format contacts
const formattedContacts = results.map(contact => ({
  id: contact.id,
  name: contact.name || 'Unknown',
  phone_number: contact.phone_number || 'No phone',
  email: contact.email || '',
  company: contact.company || '',
  created_at: contact.created_at || null
}));

// Build message
let message = `✅ Found ${formattedContacts.length} contact${formattedContacts.length > 1 ? 's' : ''} matching "${searchTerm}":\n\n`;

formattedContacts.forEach((contact, index) => {
  message += `${index + 1}. **${contact.name}**\n`;
  message += `   📱 ${contact.phone_number}\n`;
  if (contact.email) message += `   ✉️ ${contact.email}\n`;
  if (contact.company) message += `   🏢 ${contact.company}\n`;
  message += `\n`;
});

return [{
  json: {
    success: true,
    message,
    contacts: formattedContacts,
    count: formattedContacts.length,
    intent: 'search',
    searchTerm
  }
}];

// Format insert response
const contact = $input.first().json;

return [{
  json: {
    success: true,
    message: `✅ Contact "${contact.name}" added successfully!`,
    intent: 'insert',
    contact: {
      id: contact.id,
      name: contact.name,
      phone_number: contact.phone_number,
      email: contact.email || '',
      company: contact.company || '',
      created_at: contact.created_at
    }
  }
}];

// Extract and validate input from AI agent
const rawInput = $input.first().json;

// Handle both wrapped (query) and flat formats
let input;
if (rawInput.query && typeof rawInput.query === 'object') {
  // Input is wrapped in "query" object
  input = rawInput.query;
} else {
  // Input is flat
  input = rawInput;
}

// Get intent (search or insert)
const intent = input.intent || 'search';

// Extract fields
const contactName = (input.contact_name || '').trim();
const agentId = (input.agent_id || '').trim();
const contactPhone = (input.contact_phone || '').trim();
const email = (input.email || '').trim();
const company = (input.company || '').trim();

// Validate required fields
if (!contactName || contactName.length < 2) {
  return [{
    json: {
      error: true,
      success: false,
      message: "❌ Please provide a valid contact name (2+ characters)."
    }
  }];
}

if (!agentId || agentId.length < 5) {
  return [{
    json: {
      error: true,
      success: false,
      message: "❌ Invalid or missing agent_id."
    }
  }];
}

// For INSERT, validate phone
if (intent === 'insert') {
  if (!contactPhone || contactPhone.length < 10) {
    return [{
      json: {
        error: true,
        success: false,
        message: "❌ Please provide a valid phone number (10+ digits)."
      }
    }];
  }
}

// Clean phone number (remove spaces, +, etc.)
function cleanPhone(phone) {
  if (!phone) return '';
  let cleaned = phone.replace(/[\s\-()]/g, ''); // Remove spaces, dashes, parentheses
  cleaned = cleaned.replace(/^\+/, ''); // Remove +
  if (cleaned.startsWith('0')) cleaned = '92' + cleaned.substring(1); // Handle 0 prefix for Pakistan
  return cleaned.replace(/\D/g, ''); // Keep only digits
}

const cleanedPhone = cleanPhone(contactPhone);

// Sanitize name
const sanitizedName = contactName
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') // Remove control chars
  .substring(0, 100);

// Return validated data
return [{
  json: {
    success: true,
    error: false,
    intent: intent,
    contact_name: sanitizedName,
    agent_id: agentId,
    contact_phone: cleanedPhone,
    email: email.substring(0, 100),
    company: company.substring(0, 100),
    searchPattern: `%${sanitizedName.toLowerCase()}%`
  }
}];

// Return error response from validation
const errorData = $input.first().json;

return [{
  json: {
    success: false,
    message: errorData.message,
    contacts: [],
    count: 0,
    intent: 'error'
  }
}];

const thread = $json.threadData;
const reply = $json.originalMessage;

return [{
  json: {
    threadId: thread.threadId,
    originalMessageId: thread.originalMessageId,
    originalSenderPhone: thread.originalSender,
    replyFromPhone: reply.senderPhone.replace('+', ''),
    replyContent: reply.message,
    replyMessageId: reply.messageId,
    agentId: reply.agentId,
    userId: reply.userId,
    originalConversationId: thread.originalConversationId,
    currentConversationId: reply.conversationId,
    originalMessage: thread.originalMessage
  }
}];

const data = $('Process Reply3').item.json;

const notificationMessage = `📬 *Reply Received*

From: ${data.replyFromPhone}
Reply: "${data.replyContent}"

Original message: "${data.originalMessage || 'N/A'}"
Received at: ${new Date().toLocaleString()}`;

return [{
  json: {
    numbers: data.originalSenderPhone,
    message: notificationMessage,
    messageType: 'TEXT',
    agentId: data.agentId
  }
}];

const data = $('Process Reply3').item.json;

const confirmationMessage = `✅ *Reply Acknowledged*

Your message has been delivered to the sender.
Thank you for your response!`;

return [{
  json: {
    numbers: data.replyFromPhone,
    message: confirmationMessage,
    messageType: 'TEXT',
    agentId: data.agentId
  }
}];

// Get the meeting data from the previous node
const meetingData = $input.first().json;

// Get the original message data
const messageData = $('Log Message to DB3').first().json;

// Get the agentId
const agentId = $('Is Valid Message?3').first().json.agentId;

// Check if we have a pending meeting (contact_phone exists means query returned a result)
const hasPendingMeeting = meetingData && meetingData.contact_phone;

// Return combined data with a flag indicating if there's a pending meeting
return [{
  json: {
    hasPendingMeeting: !!hasPendingMeeting,
    meeting: hasPendingMeeting ? meetingData : null,
    message: messageData,
    agentId: agentId
  }
}];

// --- Extract Inputs ---
const input = $input.first().json;
const message = $('Is Valid Message?3').first().json.message || null;
const agentId = input.agentId || null;

// --- Validate Meeting Data ---
if (!input || !input.meeting) {
  return [{
    json: {
      error: true,
      success: false,
      message: '❌ No meeting data found in input.'
    }
  }];
}

const meeting = input.meeting;
const hasPendingMeeting = !!input.hasPendingMeeting;
const meetingId = meeting.id || null;
const userId = meeting.user_id || null;
const title = (meeting.title || '').trim();
const dateTime = (meeting.date_time || '').trim();
const purpose = (meeting.purpose || '').trim();
const location = (meeting.location || 'Virtual').trim();
const contactName = (meeting.contact_name || '').trim();
const contactPhone = (meeting.contact_phone || '').trim();
const meetingStatus = (meeting.status || '').trim();

const errors = [];
if (!meetingId) errors.push('Meeting ID is required.');
if (!userId) errors.push('User ID is required.');
if (!agentId) errors.push('Agent ID is required.');
if (!contactName) errors.push('Contact name is required.');
if (!contactPhone || contactPhone.length < 10 || isNaN(Number(contactPhone))) {
  errors.push('Valid contact phone number required (numeric, min 10 digits).');
}
if (!title) errors.push('Meeting title is required.');
if (!dateTime) errors.push('Meeting date and time required.');
if (!purpose) errors.push('Meeting purpose is required.');

if (errors.length > 0) {
  return [{
    json: {
      error: true,
      success: false,
      message: `❌ Validation failed:\n${errors.join('\n')}`
    }
  }];
}

// --- Construct Output for Subworkflow ---
return [{
  json: {
    hasPendingMeeting,
    meetingId,
    userId,
    agentId,
    contactName,
    contactPhone: `+${contactPhone.replace(/\+/g, '')}`,
    title,
    dateTime,
    purpose,
    location,
    meetingStatus,
    createdAt: meeting.created_at || null,
    message,
    messageSuccess: input.message?.success || false,
    timestamp: new Date().toISOString(),
    success: true
  }
}];

const messageData = $('Is Valid Message?3').item.json;

return [{
  json: {
    senderPhone: messageData.senderPhone.replace('+', ''),
    cleanPhone: messageData.senderPhone.replace('+', ''),
    originalMessage: messageData
  }
}];

const threadResult = $input.first().json;
const hasActiveThread = Boolean(threadResult && threadResult.id);

let originalMessage = {};
try {
  originalMessage = $('Check if Reply to Thread2').first().json.originalMessage;
} catch (e) {
  originalMessage = {};
}

// Check if this is actually a reply to an active thread
let isActualReply = false;
let threadData = null;

if (hasActiveThread && originalMessage.conversationId) {
  // The current message sender should match the thread's recipient_phone
  const currentSender = String(originalMessage.conversationId).replace(/\+/g, '');
  const threadRecipient = String(threadResult.recipient_phone).replace(/\+/g, '');

  // Also verify the agent matches
  const agentMatches = originalMessage.agentId === threadResult.agent_id;

  if (currentSender === threadRecipient && agentMatches) {
    isActualReply = true;
    threadData = {
      threadId: threadResult.id,
      originalMessageId: threadResult.original_message_id,
      originalMessage: threadResult.original_message,
      originalSender: threadResult.sender_phone,
      originalConversationId: threadResult.original_conversation_id,
      timeSinceSent: new Date() - new Date(threadResult.sent_at || Date.now())
    };
  }
}

return [{
  json: {
    isReply: isActualReply,
    threadData: threadData,
    originalMessage: originalMessage,
    debug: {
      hasThread: hasActiveThread,
      currentSender: originalMessage.conversationId,
      threadRecipient: threadResult?.recipient_phone,
      agentMatch: originalMessage.agentId === threadResult?.agent_id,
      threadKeys: Object.keys(threadResult || {})
    }
  }
}];

// Prepare data specifically for WhatsApp API endpoint
// Get data from the "Should Track Thread?" node which has all the original data
const inputData = $('Should Track Thread?2').item.json;

// Map fields to match API expectations
const payload = {
  agentId: inputData.agentId || '',
  to: inputData.recipientPhone || inputData.numbers || inputData.phone_number || '',
  message: inputData.message || ''
};

// Clean phone number - ensure it's properly formatted
if (payload.to && payload.to.startsWith('+')) {
  payload.to = payload.to.substring(1);
}

return [{
  json: payload
}];

const aiResponse = $input.first().json;
const message = aiResponse.message || '';
const messageLower = message.toLowerCase();

// ============================================================
// AI MESSAGE DETECTION - PRIMARY CHECK
// ============================================================
// CRITICAL: Messages generated by the AI agent should NEVER be tracked
// This prevents infinite loops and database pollution
// ============================================================

// 1. Check for AI-GENERATED MESSAGE patterns
const aiGeneratedPatterns = [
  '👋 welcome to your personal business assistant',
  'please select an option:',
  'i can help you manage',
  'reply with the number',
  '1️⃣', '2️⃣', '3️⃣', '4️⃣', '5️⃣', '6️⃣',
  '📅 meeting options',
  'please select how you\'d like to view',
  '✅ message sent successfully',
  '✅ meeting scheduled',
  '✅ meeting invitation sent',
  '✅ contact',
  'added successfully',
  'invitation sent',
  'has been sent',
  'has been scheduled',
  'has been added',
  'meeting 1:',
  'meeting 2:',
  'here are your',
  'no meetings found',
  'retrieved',
  'search results',
  'i found the following',
  'i found',
  '📬',
  '🔄 erp/crm update feature',
  'returning to main menu',
  'returning to menu',
  '📨 message preview',
  'this message will be sent to',
  '📅 meeting invitation preview',
  'this invitation will be sent to',
  'please reply \'yes\' to send',
  'please reply \'yes\' to confirm',
  'reply \'yes\' to send',
  'or \'no\' to cancel',
  'meeting details:',
  'meeting details summary:',
  'organized by:',
  'the meeting invitation has been sent',
  '━━━━━━━━━━━━━━━━━━━━━━━━━━━',
  'please provide:',
  'please provide the following',
  'i need the following information',
  'would you like to',
  'what would you like',
  'who would you like',
  'what is the',
  'which contact',
  'ready to add this contact',
  'contact not found'
];

// 2. Check for structured formatting (strong indicator of AI responses)
const hasMultipleBullets = (message.match(/•/g) || []).length >= 2;
const hasMultipleEmojis = (message.match(/[📅📨✅🔄👋💡📍📋📬]/g) || []).length >= 2;
const hasDecorators = message.includes('━━━━━━') || message.includes('═══════');
const hasStructuredNewlines = (message.match(/\n\n/g) || []).length >= 2;

// 3. Check message length (AI responses are typically longer than user input)
const isLongMessage = message.length > 200;

// 4. Check for AI pattern matches
const containsAIPattern = aiGeneratedPatterns.some(pattern => 
  messageLower.includes(pattern.toLowerCase())
);

// ============================================================
// FINAL AI MESSAGE DETECTION
// ============================================================
// A message is AI-generated if it matches ANY of these criteria:
const isAIGeneratedMessage = 
  containsAIPattern || // Contains known AI patterns
  (hasMultipleBullets && isLongMessage) || // Structured with bullets
  (hasMultipleEmojis && isLongMessage) || // Multiple emojis + long
  (hasDecorators) || // Has decorative lines
  (hasStructuredNewlines && isLongMessage) || // Well-formatted paragraphs
  (hasMultipleBullets && hasMultipleEmojis); // Structured formatting

// ============================================================
// THREAD TRACKING DECISION
// ============================================================
// AI-generated messages should NEVER be tracked
// This prevents them from being stored in message_threads table
// ============================================================

let shouldTrackThread = false;
let skipReason = null;

if (isAIGeneratedMessage) {
  // AI messages are NEVER tracked
  shouldTrackThread = false;
  skipReason = 'AI_GENERATED_MESSAGE';
} else {
  // For non-AI messages (actual user responses), apply normal tracking logic

  // Only track very specific question patterns that expect single answers
  const singleAnswerQuestions = [
    'who would you like to send a message to',
    'please provide their name',
    'what message would you like to send',
    'what is the meeting title',
    'what is the purpose',
    'what is the location'
  ];

  const isSingleAnswer = singleAnswerQuestions.some(pattern => 
    messageLower.includes(pattern)
  );

  // Even single-answer questions from AI shouldn't be tracked
  shouldTrackThread = isSingleAnswer && !isAIGeneratedMessage;
  skipReason = shouldTrackThread ? null : 'NOT_TRACKABLE_QUESTION';
}

// ============================================================
// RETURN RESULT
// ============================================================

return [{
  json: {
    ...aiResponse,
    shouldTrackThread: shouldTrackThread,
    isAIMessage: isAIGeneratedMessage,
    skipReason: skipReason,
    debug: {
      messageLength: message.length,
      containsAIPattern,
      hasMultipleBullets,
      hasMultipleEmojis,
      hasDecorators,
      hasStructuredNewlines,
      isLongMessage,
      isAIGeneratedMessage,
      finalDecision: shouldTrackThread,
      messagePreview: message.substring(0, 150)
    }
  }
}];

const inputData = $('Check if Reply to Thread2').item.json;
const reply = inputData.originalMessage;

return [{
  json: {
    replyFromPhone: reply.senderPhone.replace('+', ''),
    replyContent: reply.message,
    replyMessageId: reply.messageId,
    agentId: reply.agentId,
    userId: reply.userId,
    currentConversationId: reply.conversationId,
    senderPhone: reply.senderPhone,
    senderName: reply.senderName,
    timestamp: reply.timestamp
  }
}];

const data = $('Process Reply4').item.json;

// Get current date/time in Pakistan timezone
const now = new Date();
const pakistanTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Karachi' }));

const day = String(pakistanTime.getDate()).padStart(2, '0');
const month = String(pakistanTime.getMonth() + 1).padStart(2, '0');
const year = pakistanTime.getFullYear();

let hours = pakistanTime.getHours();
const minutes = String(pakistanTime.getMinutes()).padStart(2, '0');
const ampm = hours >= 12 ? 'PM' : 'AM';
hours = hours % 12 || 12; // Convert to 12-hour format

const formattedDate = `${day}/${month}/${year}, ${hours}:${minutes} ${ampm}`;

// TODO: Add sender name/contact name here
const senderName = $('Webhook1').first().json.body.metadata.senderName; 

const notificationMessage = `📬 *Message Notification*
From: ${senderName}
Message: "${data.replyContent}"
Received at: ${formattedDate}`;

return [{
  json: {
    numbers: $input.first().json.agent_phone_number,
    message: notificationMessage,
    messageType: 'TEXT',
    agentId: data.agentId
  }
}];

const data = $('Process Reply4').item.json;

const confirmationMessage = `✅ *Reply Acknowledged*

Your message has been delivered to the sender.
Thank you for your response!`;

return [{
  json: {
    numbers: data.replyFromPhone,
    message: confirmationMessage,
    messageType: 'TEXT',
    agentId: data.agentId
  }
}];

// Get the message data from the Is Valid Message?1 node
const messageData = $('Is Valid Message?3').item.json;

// Validate required fields
if (!messageData || !messageData.messageId || !messageData.message) {
  throw new Error('Invalid message data: missing required fields');
}

return [{
  json: {
    messageId: messageData.messageId,
    chatInput: messageData.message,
    senderPhone: messageData.senderPhone,
    senderName: messageData.senderName,
    conversationId: messageData.conversationId,
    agentPhone: messageData.agentPhone,
    agentId: messageData.agentId,
    userId: messageData.userId,
    timestamp: messageData.timestamp,
    messageType: messageData.messageType,
    direction: messageData.direction,
    rawFrom: messageData.rawFrom,
    isFromAgent: messageData.isFromAgent
  }
}];

const body = $input.first().json.body || {};

const messageId = body.id || body.messageId;
const senderPhone = body.from;
const agentPhone = body.agent || body.to;
const message = body.content || body.textContent || body.transcribedText;
const timestamp = body.timestamp;
const agentId = body.agentId;
const userId = body.user_id;
const conversationId = body.from;
const direction = body.direction || body.metadata?.direction;
const rawFrom = body.rawFrom || body.from;
const messageType = body.messageType || body.type;

// Validate required fields
if (!senderPhone || !message || !messageId) {
  return [{
    json: {
      error: true,
      skipProcessing: true,
      errorType: 'MISSING_FIELDS',
      message: 'Missing required fields: senderPhone, message, or messageId'
    }
  }];
}

// Skip if message ID starts with 'BAE' (agent message pattern)
if (messageId && messageId.startsWith('BAE')) {
  return [{
    json: {
      error: true,
      skipProcessing: true,
      errorType: 'FROM_AGENT',
      message: 'Skipping agent message (ID pattern: BAE prefix)'
    }
  }];
}

// Skip if direction is 'outgoing' (sent by agent)
if (direction === 'outgoing') {
  return [{
    json: {
      error: true,
      skipProcessing: true,
      errorType: 'FROM_AGENT',
      message: 'Skipping outgoing message from agent'
    }
  }];
}

// Skip if sender phone matches agent phone
if (senderPhone === agentPhone) {
  return [{
    json: {
      error: true,
      skipProcessing: true,
      errorType: 'FROM_AGENT',
      message: 'Skipping agent message (phone match)'
    }
  }];
}

// Skip very long messages (likely from agent)
if (message && message.length > 200) {
  return [{
    json: {
      error: true,
      skipProcessing: true,
      errorType: 'FROM_AGENT',
      message: 'Skipping agent message (long message > 200 chars)'
    }
  }];
}

// Sanitize function
const sanitize = (str) => {
  if (typeof str !== 'string') return str;
  return str.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '').substring(0, 5000);
};

// Extract sender name
const extractName = (rawFrom) => {
  if (!rawFrom) return 'User';
  const phoneMatch = rawFrom.match(/^(\d+)@/);
  return phoneMatch ? phoneMatch[1] : 'User';
};

// Return validated and sanitized message data
return [{
  json: {
    messageId: sanitize(messageId),
    conversationId: sanitize(conversationId),
    senderPhone: sanitize(senderPhone),
    senderName: sanitize(extractName(rawFrom)),
    message: sanitize(message).trim(),
    timestamp: timestamp || new Date().toISOString(),
    agentId: sanitize(agentId),
    userId: sanitize(userId),
    agentPhone: sanitize(agentPhone),
    direction: direction,
    rawFrom: sanitize(rawFrom),
    messageType: messageType || 'text',
    isFromAgent: false
  }
}];

